import React, { useState, useCallback } from 'react';
import TextField from '@mui/material/TextField';
import Autocomplete from '@mui/material/Autocomplete';
import { debounce } from 'lodash';

const fakeBoardApi = (query) => {
  return new Promise(resolve => {
    setTimeout(() => {
      const allBoards = [{ title: 'Project A' }, { title: 'Project B' }, { title: 'Another Board' }];
      if (!query) return resolve([]);
      const filtered = allBoards.filter(b => b.title.toLowerCase().includes(query.toLowerCase()));
      resolve(filtered);
    }, 300);
  });
};

const AutocompleteSearch = () => {
  const [options, setOptions] = useState([]);

  const fetchBoards = async (searchQuery) => {
    const results = await fakeBoardApi(searchQuery);
    setOptions(results);
  };

  const debouncedFetch = useCallback(debounce(fetchBoards, 500), []);

  const handleInputChange = (event, newInputValue) => {
    debouncedFetch(newInputValue);
  };

  return (
    <Autocomplete
      freeSolo
      options={options}
      getOptionLabel={(option) => option.title || ''}
      onInputChange={handleInputChange}
      renderInput={(params) => (
        <TextField {...params} label="Search Boards..." variant="outlined" size="small" />
      )}
    />
  );
};

export default AutocompleteSearch;

